def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    import os

    # Load modified presentation
    prs = Presentation(modified_ppt_path)
    slide_number_count = 0
    for idx in range(1, len(prs.slides)):
        slide = prs.slides[idx]
        found_number = False
        # Check for visible slide number shape
        for shape in slide.shapes:
            if shape.has_text_frame:
                text = shape.text.strip()
                # Accept numbers that match slide index+1
                if text == str(idx + 1):
                    found_number = True
                    break
        if found_number:
            slide_number_count += 1
    expected = len(prs.slides) - 1
    if expected == 0:
        return "No non-title slides to check.", 1.0
    score = slide_number_count / expected
    if score < 1.0:
        return f"{slide_number_count} of {expected} non-title slides have visible slide numbers.", score
    return "All non-title slides have visible slide numbers.", score

def compute_score() -> tuple[str, float]:
    from pptx import Presentation

    prs = Presentation(modified_ppt_path)
    # Assume slide 0 is the title slide
    slide = prs.slides[0]
    found_number = False
    for shape in slide.shapes:
        if shape.has_text_frame:
            text = shape.text.strip()
            if text == '1':
                found_number = True
                break
    if found_number:
        return "Title slide contains a visible slide number.", 0.0
    return "Title slide does not contain a visible slide number.", 1.0

