def compute_score() -> tuple[str, float]:
    # Only slide modifications that add a slide number shape are permitted
    count_bad = 0
    for (orig, mod) in ppt_diff.modified_slides:
        # Compare element counts
        if mod.element_count > orig.element_count:
            # If the difference is more than 1, likely extraneous content
            if mod.element_count - orig.element_count > 1:
                count_bad += 1
        elif mod.element_count < orig.element_count:
            count_bad += 1
    if count_bad > 0:
        return f"{count_bad} slides have extraneous layout/element changes.", 0.0
    return "No extraneous layout/element changes other than slide numbers.", 1.0
